            return null;
        } finally {
            if (xmlStream != null) {
                try {
                    xmlStream.close();
                } catch (Exception e) {
                    // Ignore close exception
                }
            }
        }
    }

    /**
     * Escapes special characters in XPath string literals to prevent XPath injection.
     * Replaces single quotes with escaped version for XPath expressions.
     */
    private String escapeXPathString(String input) {
        if (input == null) {
            return "";
        }
        // Escape single quotes by doubling them in XPath string literals
        return input.replace("'", "''");
    }
